#!/usr/bin/env bash
set -euo pipefail
TARGET="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
cd "$TARGET"
if [ ! -d .git ]; then echo "❌ $TARGET is not a git repo."; exit 1; fi
b64dec(){ base64 --decode 2>/dev/null || base64 -D; }
write(){ mkdir -p "$(dirname "$1")"; printf '%s' "$2" | b64dec > "$1"; echo "  ✓ $1"; }
echo "Applying Freddy Fix It update (SEO + conversion + recruitment + mobile fixes)…"
write "CLAUDE.md" ""
write "index.html" ""
write "public/sitemap.xml" ""
write "src/App.tsx" ""
write "src/components/Footer.tsx" ""
write "src/components/NotificationBell.tsx" ""
write "src/components/ReportProblem.tsx" ""
write "src/components/RespondToClaim.tsx" ""
write "src/pages/AdminDashboard.tsx" ""
write "src/pages/ClientDashboard.tsx" ""
write "src/pages/ContractorDashboard.tsx" ""
write "src/pages/ContractorProfile.tsx" ""
write "src/pages/ForContractors.tsx" ""
write "src/pages/Home.tsx" ""
write "src/pages/ServiceLanding.tsx" ""
write "src/pages/ServicesIndex.tsx" ""
write "src/pages/UserAgreement.tsx" ""
write "supabase/functions/create-payment-intent/index.ts" ""
write "supabase/functions/stripe-webhook/index.ts" ""
git add -A
git commit -m "Mobile fixes (notif dropdown, contractor earnings/profile grids, admin tabs) + drop Calgary from hero + /for-contractors + SEO pages (supersedes prior installers)" || { echo "Nothing to commit."; }
git push
echo "✅ Changes committed and pushed. Hard-refresh the site with Cmd+Shift+R."
